sys_script_include.script:
var FMStreakTracker = Class.create();
FMStreakTracker.prototype = {
    initialize: function() {},

    /**
     * Updates the user's streak. Checks if user completed a task today and increments streak_count.
     * @param {string} userProfileSysId - sys_id of the user profile
     */
    updateStreak: function(userProfileSysId) {
        var today = new GlideDateTime();
        var todayStr = today.getLocalDate().toString();

        // Check if user completed a task today
        var taskGr = new GlideRecord('x_2063628_flowmi_0_fm_task');
        taskGr.addQuery('assigned_to', userProfileSysId);
        taskGr.addQuery('status', 'completed');
        taskGr.addQuery('completed_date', '>=', todayStr);
        taskGr.query();

        if (taskGr.hasNext()) {
            var profile = new GlideRecord('x_2063628_flowmi_0_fm_user_profile');
            if (profile.get(userProfileSysId)) {
                var currentStreak = parseInt(profile.getValue('streak_count')) || 0;
                profile.setValue('streak_count', currentStreak + 1);
                profile.update();
            }
        }
    },

    /**
     * Resets streak to 0 if no task was completed yesterday.
     * @param {string} userProfileSysId - sys_id of the user profile
     */
    resetStreakIfMissed: function(userProfileSysId) {
        var yesterday = new GlideDateTime();
        yesterday.addDaysLocalTime(-1);
        var yesterdayStr = yesterday.getLocalDate().toString();

        var today = new GlideDateTime();
        var todayStr = today.getLocalDate().toString();

        // Check if user completed a task yesterday
        var taskGr = new GlideRecord('x_2063628_flowmi_0_fm_task');
        taskGr.addQuery('assigned_to', userProfileSysId);
        taskGr.addQuery('status', 'completed');
        taskGr.addQuery('completed_date', '>=', yesterdayStr);
        taskGr.addQuery('completed_date', '<', todayStr);
        taskGr.query();

        if (!taskGr.hasNext()) {
            var profile = new GlideRecord('x_2063628_flowmi_0_fm_user_profile');
            if (profile.get(userProfileSysId)) {
                profile.setValue('streak_count', 0);
                profile.update();
            }
        }
    },

    /**
     * Returns bonus XP for the given streak count.
     * Streak 3-6: +5 XP
     * Streak 7-13: +10 XP
     * Streak 14-29: +20 XP
     * Streak 30+: +50 XP
     * @param {number} streakCount - current streak count
     * @returns {number} bonus XP amount
     */
    getStreakBonus: function(streakCount) {
        var streak = parseInt(streakCount) || 0;

        if (streak >= 30) {
            return 50;
        } else if (streak >= 14) {
            return 20;
        } else if (streak >= 7) {
            return 10;
        } else if (streak >= 3) {
            return 5;
        }

        return 0;
    },

    type: 'FMStreakTracker'
};
